UPDATE jobs SET user_contributed_json = '{"way":"점화·발파·화약관리원이 되려면 화약류 취급과 관련된 전문 자격을 취득해야 한다.[1] 화약류관리기사 자격증은 한국산업인력공단이 시행하는 국가기술자격으로, 관련 학과 졸업 또는 일정 경력 후 필기·실기 시험을 통해 취득할 수 있다.[2] 취업 경로는 광산, 건설회사(터널·도로·댐 공사), 채석장, 군 관련 시설 등 발파 작업이 필요한 현장이다.[1] 현장에서는 화약류 안전관리법에 따라 반드시 자격증 보유자가 발파 작업을 수행해야 하므로 자격증이 취업의 핵심 조건이다.[2] 경력이 쌓이면 발파 팀장, 화약류 안전관리자, 또는 전문 컨설턴트로 성장할 수 있다.[1]","overviewSalary":{"sal":"연봉 중위값은 약 3,200만 원이다.[1] 건설·광산 현장의 위험수당이 포함되며, 경력과 현장 규모에 따라 4,000만 원 이상도 가능하다.[2] 야간 발파나 특수 공법 현장에서는 추가 수당이 지급된다.[1]","source":"워크넷, 커리어넷 직업백과(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 다소 감소할 것으로 전망된다.[1] 건설경기 변동과 환경 규제 강화로 발파 작업이 줄어드는 추세이나, 지하 인프라(지하철·터널) 공사는 꾸준히 수요가 있다.[2] 자동화 기술 도입으로 일부 작업이 대체될 수 있어 전문성 강화가 중요하다.[1]","source":"커리어넷 직업백과(2024)"},"trivia":"화약류 1kg이 폭발하면 TNT 환산으로 수백 배의 에너지가 방출되어, 단 한 번의 발파로 아파트 수십 층 높이의 암석을 제거할 수 있다.[1] 발파 전에는 반경 수백 미터 내 주민 대피와 소음·진동 측정이 의무화되어 있다.[2] 조선시대에는 화약을 다루는 직책이 ''화통군''이라 불렸으며, 화포와 화전 제작의 핵심 인력이었다.[3] 현대 발파 기술에서 ''밀리초 단위'' 지연뇌관을 활용하면 진동을 최소화하면서 원하는 방향으로 암석을 붕괴시킬 수 있다.[1]","detailWlb":{"wlb":"낮음","social":"보통이하","wlbDetail":"건설·광산 현장의 특성상 조기 출근과 날씨·공정에 따른 불규칙한 근무가 많다. 야간 발파, 주말 공사가 빈번하며 현장이 지방 오지에 위치하는 경우 숙소 생활을 해야 하는 경우도 있다. 폭발물 취급에 따른 상시 긴장감과 사고 위험으로 심리적 스트레스가 크다.","socialDetail":"일반 시민에게 잘 알려지지 않은 직종이나, 건설·광산·도시개발 현장에서 없어서는 안 될 핵심 기능 인력이다. 국가 인프라(도로, 터널, 지하철) 건설에 직접 기여하며, 화약류 안전관리를 통해 사고 예방에도 역할을 한다."},"detailReady":{"curriculum":["화약류 관련 학과(자원공학, 광산공학, 안전공학) 입학 또는 관련 훈련기관 등록","화약류관리기사 필기 시험 준비: 화약학, 발파공학, 안전관리 과목 학습","실기 시험(발파 작업 실무) 준비: 현장 실습 병행","폭발물 안전 취급 훈련 및 관련 법규(화약류 안전관리법) 이수"],"recruit":["건설회사(터널·도로 공사 전문업체) 발파 기술 인력 채용","광산회사(석회석, 골재 채석장) 현장 발파원 채용","군부대 관련 화약 취급 전문 업체","발파 전문 하도급 업체(한국발파공업협회 회원사)"],"training":["화약류관리기사 → 화약류관리기술사 상위 자격 취득","건설안전기사 추가 취득으로 현장 안전관리자 역할 확대","발파 팀장·현장소장으로 관리직 진출","화약류 수입·유통 업체 컨설턴트로 전직"]},"sidebarJobs":["소방관","경찰관","항공기조종사","선박기관사","여행사무원"],"sidebarMajors":["안전공학과","화학공학과","지질학과","환경공학과"],"sidebarCerts":["화약류관리기사","발파기사","화약류관리기술사","건설안전기사","위험물산업기사"],"heroTags":["화약","발파","화약류관리기사","터널공사","광산","폭발물"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=283"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=283"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=283"},{"id":2,"text":"고용노동부 직업전망","url":"https://www.moel.go.kr/"}],"trivia":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=283"},{"id":2,"text":"화약류 안전관리법","url":"https://www.law.go.kr/"},{"id":3,"text":"한국민족문화대백과사전","url":"https://encykorea.aks.ac.kr/"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=283"}],"detailWlb.socialDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=283"}]}}' WHERE id = '1765283500599182';

UPDATE jobs SET user_contributed_json = '{"way":"선박갑판원이 되려면 관련 자격증을 취득하거나 해양계 학교를 졸업하는 것이 유리하다.[1] 소형선박조종사나 6급 항해사 자격증을 취득한 후 해운회사, 어선업체, 선박 운항 회사에 취업하는 것이 일반적 경로이다.[2] 한국해양수산연수원(KIMFT)에서 기본 안전교육(STCW)을 이수해야 승선이 가능하다.[1] 초보 갑판원으로 시작하여 항해 경험을 쌓은 뒤 3등 항해사, 2등 항해사로 승진하며, 이를 위해 항해사 면허 시험에 합격해야 한다.[2] 한국해양대학교·목포해양대학교 항해학과 졸업 시 3등 항해사로 직접 취업하는 경로도 있다.[1]","overviewSalary":{"sal":"연봉 중위값은 약 3,400만 원이다.[1] 승선 기간 중 숙식이 무료 제공되며, 위험수당·외항 수당 등이 포함된다.[2] 외항 상선의 경우 4,000~6,000만 원에 달하기도 하며, 내항 연안선이나 어선은 상대적으로 낮다.[1]","source":"워크넷, 한국해기사협회(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 현 수준을 유지하거나 소폭 감소할 것으로 전망된다.[1] 국제 해운 물동량은 꾸준하지만 자동화 기술과 무인선박 기술 개발로 장기적으로는 인력 수요가 감소할 수 있다.[2] 반면, 국내 연안 여객선·해양 관광업은 성장세로 관련 수요는 지속된다.[1]","source":"커리어넷 직업백과, 해양수산부(2024)"},"trivia":"전 세계 무역량의 약 80%가 선박으로 운반된다. 갑판원이 없으면 현대 무역 체계 자체가 작동하지 않는다.[1] ''갑판(甲板)''이라는 용어는 한자로 ''으뜸 판자''를 뜻하며, 선박의 가장 위층 플랫폼을 가리킨다.[2] 일부 초대형 컨테이너선(ULCV)은 갑판 길이가 400미터로, 에펠탑 높이보다 길다.[3] 갑판원은 닻(anchor) 투하와 회수 작업을 담당하는데, 대형 선박의 닻 무게는 20~30톤에 달한다.[1]","detailWlb":{"wlb":"낮음","social":"보통이하","wlbDetail":"승선 기간 중 가족과 장기간 이별해야 하는 것이 가장 큰 어려움이다. 외항선의 경우 3~6개월 연속 승선이 일반적이며, 공해 한가운데서의 고립감과 조난 위험도 존재한다. 교대 근무(4시간 당직-8시간 휴식)로 수면 패턴이 불규칙하며, 시차와 기상 변화에 지속적으로 노출된다.","socialDetail":"눈에 보이지 않는 곳에서 국가 물류와 무역을 뒷받침하는 직업이다. 해운 산업은 국가 경제와 직결되지만, 사회적 인지도는 낮은 편이다. 최근 항만 물류·해양 관광 성장으로 인식이 개선되고 있다."},"detailReady":{"curriculum":["한국해양대·목포해양대 항해학과(4년) 또는 해양고등학교 진학","기본 안전교육(STCW) 이수: 한국해양수산연수원(KIMFT)","소형선박조종사 자격증 취득 준비(1종·2종)","영어 능력 강화: TOEIC 600점 이상 권장 (외항선 취업 시)"],"recruit":["한국해운조합·한국선주협회 구인공고 통해 연안 선박 취업","한국해양대·목포해양대 취업처 통해 외항 상선 취업","어선원모집센터(연근해·원양 어선 전문)","한국선원취업지원센터 경유 해외 선사 취업"],"training":["3등 항해사 → 2등 항해사 → 1등 항해사 → 선장 승진 경로","해기사 면허(6급→5급→4급) 단계적 취득","해양 안전 전문가, 항만 물류 관리직으로 전직","선박 검사원, 해운 컨설턴트로 전문화"]},"sidebarJobs":["항해사","선박기관사","어업관련종사원","항공기조종사","잠수사"],"sidebarMajors":["항해학과","해양공학과","조선공학과","수산학과"],"sidebarCerts":["소형선박조종사","6급항해사","위험물취급자","기본안전교육(STCW)","구명정조종사"],"heroTags":["갑판원","선원","해기사","항해사","승선","해운"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=323"},{"id":2,"text":"한국해양수산연수원","url":"https://www.kimft.or.kr/"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"한국해기사협회","url":"https://www.kormi.or.kr/"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=323"},{"id":2,"text":"해양수산부 통계","url":"https://www.mof.go.kr/"}],"trivia":[{"id":1,"text":"국제해사기구(IMO)","url":"https://www.imo.org/"},{"id":2,"text":"한국민족문화대백과사전","url":"https://encykorea.aks.ac.kr/"},{"id":3,"text":"해운정보서비스","url":"https://www.ksg.co.kr/"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=323"}],"detailWlb.socialDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=323"}]}}' WHERE id = '1765283326029814';

UPDATE jobs SET user_contributed_json = '{"way":"한복제조원이 되려면 한복 기능을 전문적으로 배우는 훈련기관이나 직업전문학교에 입학하거나, 한복 명장·숙련공 밑에서 도제식 교육을 받는 것이 일반적이다.[1] 한국산업인력공단 시행 한복기능사 자격증 취득이 취업에 유리하며, 한복 공방, 한복 대여점, 전통 의상 제작업체 등에 취업한다.[2] 대학교 한복구성학과나 의상학과를 통해 이론과 실기를 체계적으로 배우는 경로도 있다.[1] 경력이 쌓이면 자신의 한복 공방을 창업하거나 패션쇼·드라마·영화 의상 제작 분야로 진출할 수 있다.[2] K-드라마 한류 영향으로 해외 한복 수요가 늘면서 글로벌 시장 진출 기회도 생겨나고 있다.[1]","overviewSalary":{"sal":"연봉 중위값은 약 2,800만 원이다.[1] 명인·명장급의 경우 고가 맞춤 한복 제작으로 연 5,000만 원 이상도 가능하다.[2] 설·추석 명절 성수기에 매출이 집중되며, 자가 운영 공방은 매출 편차가 크다.[1]","source":"워크넷, 한국공예·디자인문화진흥원(2024)"},"overviewProspect":{"main":"향후 5년간 고용 규모는 현 수준을 유지하거나 소폭 증가할 것으로 전망된다.[1] K-드라마, K-콘텐츠의 세계적 인기로 한복 수요가 늘고 있으며, 웨딩·돌잔치용 한복 대여 시장도 꾸준하다.[2] 다만 대량 생산 저가 한복의 유통 확대로 전통 맞춤 한복 제작자 수는 감소 추세이며, 기성품과의 경쟁이 심화되고 있다.[1]","source":"커리어넷 직업백과, 문화체육관광부(2024)"},"trivia":"한복은 착용자의 신체 치수뿐만 아니라 계절, 격식, 색채 상징까지 고려하여 제작되는 복합 예술품이다.[1] 한복의 색상에는 음양오행 사상이 담겨 있어, 흰색(서방·금)·청색(동방·목)·적색(남방·화)·흑색(북방·수)·황색(중앙·토)의 오방색이 기본을 이룬다.[2] UNESCO는 2022년 한복을 인류무형문화유산 대표목록에 등재했다.[3] 조선시대 왕실 한복에는 실크(비단) 한 벌에 누에 수천 마리가 필요했으며, 이를 제작하는 장인은 ''봉제공방''에서 국가 관리를 받았다.[1]","detailWlb":{"wlb":"보통이상","social":"보통이상","wlbDetail":"설·추석 성수기에는 야근과 주말 작업이 불가피하나, 평상시에는 비교적 규칙적인 근무가 가능하다. 공방 운영 시에는 납품 일정에 따라 집중 작업 기간이 발생한다. 앉아서 세밀한 작업을 오래 하는 특성상 눈의 피로와 허리 부담이 있다.","socialDetail":"한국의 전통 문화를 보존하고 계승하는 직업으로, 사회적 가치와 인식이 높다. K-콘텐츠 확산으로 한복이 세계에 알려지면서 문화 홍보 기능도 함께 수행하고 있다. 명인·무형문화재 지정 시 국가로부터 지원을 받으며 전통 기술 전승자로서의 역할도 부여된다."},"detailReady":{"curriculum":["한복 관련 직업훈련원·학원 등록: 재단, 봉제, 자수 등 기초 실기","한복기능사 자격시험 준비: 필기(한복이론, 재료학) + 실기(한복 제작)","대학교 한복구성학과 또는 의류·의상학과 진학(심화 이론)","전통 자수, 염색(진사·쪽) 기법 별도 학습"],"recruit":["한복 전문 공방 및 맞춤 제작업체 취업","한복 대여점(웨딩·돌잔치 전문) 취업","방송국·영화사 의상팀 전통 의상 담당","한국공예·디자인문화진흥원 등 문화기관 연계 기회"],"training":["한복기능사 → 한복기능장 상위 자격 취득","전통 자수·매듭·염색 등 전통 공예 복합 전문가로 성장","자신의 브랜드 한복 공방 창업","해외 K-드라마·K-팝 스타일링팀과 협업 진출"]},"sidebarJobs":["양장·양복제조원","의복수선원","의상디자이너","패션디자이너","패턴사"],"sidebarMajors":["패션디자인학과","패션디자인과","의류·의상학과","섬유공학과"],"sidebarCerts":["한복기능사","한복기능장","양복기능사","패션디자인산업기사"],"heroTags":["한복","전통의상","한복기능사","맞춤한복","K-드라마","전통공예"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=421"},{"id":2,"text":"한국산업인력공단","url":"https://www.hrdkorea.or.kr/"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"한국공예·디자인문화진흥원","url":"https://www.kcdf.kr/"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=421"},{"id":2,"text":"문화체육관광부","url":"https://www.mcst.go.kr/"}],"trivia":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=421"},{"id":2,"text":"한국민족문화대백과사전","url":"https://encykorea.aks.ac.kr/"},{"id":3,"text":"유네스코 인류무형유산","url":"https://ich.unesco.org/"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=421"}],"detailWlb.socialDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=421"}]}}' WHERE id = '1765283521211660';

UPDATE jobs SET user_contributed_json = '{"way":"여행안내원이 되려면 한국관광공사가 주관하는 관광통역안내사(외국인 대상) 또는 문화체육관광부가 시행하는 국내여행안내사 자격증을 취득하는 것이 핵심 조건이다.[1] 관광통역안내사는 영어·일본어·중국어 등 외국어 능력 시험을 포함하며, 취득 후 여행사·관광기관에 취업한다.[2] 한국관광공사, 지방자치단체 문화관광해설사 프로그램을 통해 특정 지역 전문 해설사로 활동하는 경로도 있다.[1] 해외여행 가이드의 경우 해당 국가에 대한 깊은 지식과 현지어 구사 능력이 필수이며, 여행사 소속 또는 프리랜서로 활동한다.[2] 체험·생태 관광 수요 증가로 문화해설, 생태 투어, 미식 투어 등 전문 분야 가이드로 세분화되는 추세다.[1]","overviewSalary":{"sal":"연봉 중위값은 약 2,600만 원이다.[1] 프리랜서 가이드는 팁 수입이 포함되어 실수령액 편차가 크며, 성수기(5~10월)와 비성수기 간 소득 차이가 상당하다.[2] 외국어 능력과 전문 지식이 뛰어날수록 고급 투어 담당으로 더 높은 수입이 가능하다.[1]","source":"워크넷, 한국관광공사(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 보통 수준을 유지할 것으로 전망된다.[1] 코로나19 이후 회복세를 보이며 외국인 인바운드 관광이 증가하고 있어 수요가 늘고 있다.[2] 그러나 AI 가이드 앱, 오디오 가이드 등 기술 대체 가능성이 있어 개인화·전문화된 서비스 역량이 점점 더 중요해지고 있다.[1]","source":"한국관광공사, 커리어넷 직업백과(2024)"},"trivia":"관광통역안내사는 외국인에게 국내를 소개하는 ''민간 외교관''으로도 불린다.[1] 한국을 찾는 연간 외국인 관광객은 2019년 기준 1,750만 명으로, 이들 대부분이 여행안내원의 서비스를 접한다.[2] 일부 전문 가이드는 유명 팀투어 유튜버로 활동하며 수백만 구독자를 확보하기도 한다.[3] 조선시대에는 외국 사신을 접대하고 안내하는 ''접반관''이 여행안내원의 원조 격이었다.[1]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"주말과 공휴일이 오히려 성수기여서 명절·휴일 근무가 빈번하다. 해외 패키지 투어 가이드의 경우 10~14일씩 국외에 체류하며, 귀국 후 곧바로 다음 투어를 나가는 경우도 많다. 장거리 이동과 반복되는 해설로 체력적 부담이 상당하며, 외부 환경(날씨, 교통 등)에 스트레스가 크다.","socialDetail":"한국 문화와 역사를 외국인에게 알리는 문화 외교관 역할을 한다. 관광 수입 창출에 기여하며, 지역 경제 활성화에도 직접적인 역할을 한다. 최근 K-팝·한식·드라마 성지 투어 수요 증가로 한국 문화 홍보에 더욱 중요한 역할을 맡고 있다."},"detailReady":{"curriculum":["관광통역안내사 시험 준비: 외국어(영어·중국어·일본어 등) 실력 강화","관광자원해설 과목 학습: 한국 역사, 문화, 지리, 전통 풍습","한국관광공사 투어리즘 아카데미 수강","국내여행안내사 자격증(비외국어 경로) 취득"],"recruit":["여행사(패키지·인바운드 전문) 가이드 채용","한국관광공사·지자체 문화관광해설사 공모","외국계 여행사 한국 현지 가이드 계약","체험 관광 스타트업·투어 플랫폼 파트너 등록"],"training":["관광통역안내사 → 문화관광 전문 해설사로 전문화","특정 테마(한식·미술관·K-팝) 전문 가이드로 차별화","여행 콘텐츠 크리에이터(유튜브·인스타그램)와 병행","여행상품개발자, 관광 컨설턴트로 진로 전환"]},"sidebarJobs":["여행사무원","여행상품개발자","관광통역안내원","자연 및 문화해설사","호텔지배인"],"sidebarMajors":["관광경영학과","관광경영과","문화관광과","경영학과"],"sidebarCerts":["관광통역안내사","국내여행안내사","문화관광해설사","TOEIC 700+"],"heroTags":["여행가이드","관광통역안내사","여행안내원","인바운드관광","투어가이드"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=252"},{"id":2,"text":"한국관광공사","url":"https://www.visitkorea.or.kr/"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"한국관광공사","url":"https://www.visitkorea.or.kr/"}],"overviewProspect.main":[{"id":1,"text":"한국관광공사","url":"https://www.visitkorea.or.kr/"},{"id":2,"text":"문화체육관광부 관광통계","url":"https://www.mcst.go.kr/"}],"trivia":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=252"},{"id":2,"text":"한국관광공사 통계","url":"https://kto.visitkorea.or.kr/"},{"id":3,"text":"관련 매체 보도자료","url":"https://www.visitkorea.or.kr/"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=252"}],"detailWlb.socialDetail":[{"id":1,"text":"한국관광공사","url":"https://www.visitkorea.or.kr/"}]}}' WHERE id = '1765283342883899';

UPDATE jobs SET user_contributed_json = '{"way":"음식서비스관리자가 되려면 조리 현장 경력을 쌓아 관리직으로 승진하거나, 외식경영·호텔관광 관련 학과를 졸업 후 체인점·호텔 관리직으로 입사하는 경로가 있다.[1] 대형 프랜차이즈나 호텔은 매니저·슈퍼바이저 직책으로 공개채용을 진행하기도 한다.[2] 외식경영학과나 조리학과 졸업 후 현장 경험 5년 이상이면 식당 총괄 매니저나 급식 운영 관리자로 취업할 수 있다.[1] 단체급식(학교·기업·병원) 분야에서는 영양사 자격증을 보유한 급식 관리자 수요도 크다.[2] 자신의 레스토랑 창업 역시 주요 경로로, 이 경우 메뉴 개발, 원가 관리, 위생 관리까지 모두 담당하는 운영자가 된다.[1]","overviewSalary":{"sal":"연봉 중위값은 약 3,500만 원이다.[1] 대형 프랜차이즈 슈퍼바이저나 호텔 식음료부 매니저는 4,000~5,000만 원에 달하기도 한다.[2] 단체급식 영양사 겸 관리자는 공공기관 기준 3,200~3,800만 원 수준이다.[1]","source":"워크넷, 한국외식산업연구원(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 보통 수준을 유지할 것으로 전망된다.[1] 외식 산업의 꾸준한 성장과 배달·케이터링 시장 확대로 관리 인력 수요는 지속된다.[2] 단체급식(학교·복지시설) 시장도 안정적인 성장세를 보이고 있어 급식 관리 분야 수요도 유지된다.[1]","source":"커리어넷 직업백과, 한국외식산업연구원(2024)"},"trivia":"한국의 외식 산업 시장 규모는 연간 약 150조 원으로, GDP의 약 7%를 차지한다.[1] 음식서비스관리자는 단순히 음식을 감독하는 것이 아니라 식재료 원가율(F&B Cost)을 보통 25~35% 수준으로 맞추는 재무 관리도 담당한다.[2] 미슐랭 가이드 별점 레스토랑의 서비스 관리자는 수년간 별 유지를 위해 손님의 알레르기, 선호 메뉴까지 데이터베이스화한다.[3] 배달앱 등장 이후 홀 서비스 관리와 온라인 주문 관리를 동시에 담당하는 하이브리드 관리자 역할이 대두됐다.[1]","detailWlb":{"wlb":"보통이하","social":"보통이상","wlbDetail":"식당·급식 운영 시간에 맞춰 이른 아침부터 저녁까지 근무하는 경우가 많다. 주말과 공휴일이 가장 바쁜 시간이어서 명절·휴일 근무가 잦다. 직원 관리, 고객 불만 처리, 위생 점검 등 다방면의 스트레스가 동시에 발생하는 환경이다.","socialDetail":"국민의 식생활과 건강에 직접 연결되는 직업으로 사회적 중요성이 크다. 학교·병원·군대 등 단체급식 관리자는 수천 명의 식사를 책임지며 공중보건에 기여한다. 외식 문화 트렌드를 선도하는 역할도 하며, 최근 건강식·비건 메뉴 확산에 기여하는 음식서비스관리자들이 주목받고 있다."},"detailReady":{"curriculum":["외식산업학과·조리학과·식품영양학과 입학 또는 조리학원 수료","조리기능사 자격증 취득 (한식·양식·중식·일식)","위생사 자격 취득 또는 식품위생 교육 이수","외식 관련 현장 실습(인턴십) 경험 확보"],"recruit":["대형 프랜차이즈(패밀리레스토랑·카페 체인) 매니저·슈퍼바이저 공채","호텔 식음료부(F&B) 관리직 채용","학교·기업·병원 단체급식 업체(삼성웰스토리, 아워홈, CJ프레시웨이 등) 채용","케이터링 전문 업체 운영 관리직"],"training":["조리기능사 → 조리산업기사 → 조리기능장 상위 자격 취득","식품위생관리사, 영양사 자격 추가 취득","외식 창업 (독립 레스토랑 운영)","식품 컨설팅, 식당 창업 코칭, 메뉴 개발 컨설턴트로 전문화"]},"sidebarJobs":["주방장","요리연구가","영양사","바리스타","푸드스타일리스트","소믈리에","호텔지배인"],"sidebarMajors":["외식산업학과","외식산업과","식품조리학과","식품영양학과","경영학과"],"sidebarCerts":["조리기능사","조리산업기사","위생사","식품위생관리사","영양사"],"heroTags":["외식관리","식당매니저","단체급식","F&B","음식서비스"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=360"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"한국외식산업연구원","url":"https://www.kfiri.org/"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=360"},{"id":2,"text":"한국외식산업연구원","url":"https://www.kfiri.org/"}],"trivia":[{"id":1,"text":"한국외식산업연구원","url":"https://www.kfiri.org/"},{"id":2,"text":"외식산업 원가관리 가이드","url":"https://www.work.go.kr/"},{"id":3,"text":"미슐랭 가이드 공식 사이트","url":"https://guide.michelin.com/"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=360"}],"detailWlb.socialDetail":[{"id":1,"text":"한국외식산업연구원","url":"https://www.kfiri.org/"}]}}' WHERE id = '1765283411272742';

UPDATE jobs SET user_contributed_json = '{"way":"정부·공공행정전문가가 되는 가장 일반적인 경로는 국가공무원 채용시험(5급 행정고시 또는 9급·7급 공개경쟁채용시험)에 합격하는 것이다.[1] 지방자치단체의 경우 지방직 공무원 시험을 통해 시·도·군·구청 등에 입직하며, 공공기관은 별도의 공개채용이나 경력채용을 진행한다.[2] 행정학과, 정치외교학과, 경제학과, 법학과 등 사회과학 계열 전공이 유리하며, 공무원 준비학원을 통해 수험 준비를 하는 경우가 많다.[1] 일부는 민간 기업에서 경력을 쌓은 후 공공부문 전문직(계약직·임기제)으로 진입하기도 한다.[2] 외교부 외교관 후보자 선발시험(PSAT+전문 시험)을 통해 외무공무원으로 진출하는 경로도 있다.[1]","overviewSalary":{"sal":"연봉 중위값은 약 4,200만 원이다.[1] 공무원 호봉제 적용으로 안정적으로 오르며, 20년 이상 경력의 5급 사무관 기준으로는 7,000만 원 이상도 가능하다.[2] 지방직과 국가직 간에 다소 차이가 있으며, 연금·복지 혜택을 포함한 총 처우는 민간 대비 높게 평가된다.[1]","source":"인사혁신처, 커리어넷 직업백과(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 현 수준을 유지하거나 소폭 감소할 것으로 전망된다.[1] 디지털 행정 전환(AI·빅데이터 활용)으로 일부 행정 업무가 자동화되는 추세이나, 공공 서비스 확대와 복지 행정 수요 증가로 신규 인력 채용도 이어지고 있다.[2] 정부의 공공부문 비대화 억제 정책에 따라 공무원 증원에 제약이 있어 경쟁률은 높은 편이다.[1]","source":"인사혁신처, 커리어넷 직업백과(2024)"},"trivia":"대한민국 공무원 수는 약 110만 명으로 전체 취업자의 약 4%를 차지한다.[1] 5급 행정고시(국가공무원 공개경쟁채용) 경쟁률은 평균 100:1을 넘는 초고경쟁 시험으로 평균 준비 기간이 2~4년에 달한다.[2] 조선시대 과거 급제자 수(3년마다 최종 합격 33명)보다 현대 행정고시 합격자 수(연간 약 200명)가 훨씬 많지만, 인구 대비 경쟁은 오히려 더 치열하다.[3] 공무원은 헌법상 ''국민 전체에 대한 봉사자''로 정의되어 있다.[1]","detailWlb":{"wlb":"보통이상","social":"높음","wlbDetail":"육아휴직, 유연근무제 등 제도적 지원이 잘 갖춰져 있어 일·가정 양립이 민간 대비 용이하다. 다만 감사·국정감사 시즌이나 주요 정책 추진 시 야근·주말 근무가 발생할 수 있다. 민원 업무 담당자의 경우 고질적 민원인 응대로 인한 감정 소모가 크다.","socialDetail":"국가와 국민을 위해 직접 서비스하는 직업으로 사회적 신뢰도와 인식이 높다. 국가 정책 수립과 집행, 공공 서비스 제공에 직접 기여하며, 사회적 안전망을 유지하는 데 핵심적인 역할을 한다. 특히 복지·교육·안전 분야 공무원의 사회적 기여도는 매우 높게 평가된다."},"detailReady":{"curriculum":["행정학과, 정치외교학과, 법학과, 경제학과 등 사회과학 계열 전공","9급 공무원 시험 준비: 국어·영어·한국사 + 선택과목(행정학개론, 행정법 등)","7급·5급 공무원 시험 준비: 헌법·행정법·행정학·경제학 등 심화 과목","PSAT(공직적성평가) 유형 연습"],"recruit":["인사혁신처 국가공무원 공개채용시험(9급·7급·5급)","지방자치단체 지방직 공무원 시험","각 부처·공공기관 경력채용(전문직)","외교부 외교관 후보자 선발 시험"],"training":["9급→7급→5급→4급(과장)→3급(국장) 승진 경로","국제기구(UN, OECD) 진출 기회","국가안보전략연구원, 한국행정연구원 등 국책연구기관 연구직 전직","정년 후 지방의회 의원, 정당 활동 등 정치 분야 진출"]},"sidebarJobs":["외교관","경제학연구원","사회단체활동가","정부·공공행정전문가","행정사"],"sidebarMajors":["행정학과","정치외교학과","법학과","경제학과","경영학과","사회학과"],"sidebarCerts":["행정사","공인노무사","변호사","공인회계사","9급공무원"],"heroTags":["공무원","행정직","공개채용","행정고시","공공행정","국가직"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=200"},{"id":2,"text":"인사혁신처","url":"https://www.mpm.go.kr/"}],"overviewSalary.sal":[{"id":1,"text":"인사혁신처 공무원보수규정","url":"https://www.mpm.go.kr/"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=200"},{"id":2,"text":"인사혁신처 통계","url":"https://www.mpm.go.kr/"}],"trivia":[{"id":1,"text":"인사혁신처","url":"https://www.mpm.go.kr/"},{"id":2,"text":"국가직 공무원 채용정보","url":"https://gosi.kr/"},{"id":3,"text":"한국민족문화대백과사전","url":"https://encykorea.aks.ac.kr/"}],"detailWlb.wlbDetail":[{"id":1,"text":"인사혁신처","url":"https://www.mpm.go.kr/"}],"detailWlb.socialDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=200"}]}}' WHERE id = '1765283413511282';

UPDATE jobs SET user_contributed_json = '{"way":"오락시설서비스원이 되기 위해 특별한 자격증이나 학력 요건은 없다.[1] 노래방, 게임장, PC방, 볼링장, 당구장, 스크린골프장 등 오락 시설에 직접 방문하여 구직 신청하거나 알바천국·사람인·워크넷 등 구인 플랫폼을 통해 취업한다.[2] 고객 서비스 마인드와 기본적인 장비 조작 능력이 요구되며, 일부 시설(PC방 네트워크, 볼링장 장비 등)은 취업 후 자체 교육을 실시한다.[1] 장기 근속 후 매장 관리자(점장) 또는 창업으로 진출하는 경우도 있다.[2]","overviewSalary":{"sal":"연봉 중위값은 약 2,400만 원이다.[1] 최저임금 수준의 시급제가 많으며, 심야 및 주말 근무 시 가산 수당이 적용된다.[2] 직영점 관리자나 프랜차이즈 점장급은 3,000만 원 이상도 가능하다.[1]","source":"워크넷, 커리어넷 직업백과(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 다소 감소할 것으로 전망된다.[1] 스마트폰 게임과 OTT 서비스의 확산으로 전통적인 오락 시설 방문이 줄고 있다.[2] 그러나 스크린골프, 야구 시뮬레이션, VR 체험방 등 신형 오락 시설은 성장 중이어서 세부 분야에 따라 전망이 갈린다.[1]","source":"커리어넷 직업백과(2024)"},"trivia":"한국은 PC방 문화의 발상지로, 1990년대 말 PC방 붐을 계기로 스타크래프트·리니지 같은 온라인게임 산업이 세계 최강 수준으로 성장했다.[1] 노래방(karaoke room)은 한국식 혁신으로, 일본의 ''가라오케 박스''를 변형하여 개인 룸으로 진화시킨 한국 고유의 문화다.[2] 세계 최초의 스크린골프 시스템(골프존)은 한국 기업이 개발하여 현재 전 세계 9,000여 개 매장에서 운영 중이다.[3] 코인노래방의 등장 이후 단기 소비 형태가 강화되면서 오락시설서비스원의 업무 방식도 변화하고 있다.[1]","detailWlb":{"wlb":"보통이하","social":"보통이하","wlbDetail":"오락 시설의 특성상 저녁·심야 시간대가 가장 바쁘므로 야간 근무가 많고, 주말·공휴일에도 출근해야 한다. 24시간 운영 업소에서는 야간 당직을 맡는 경우도 있다. 고객 민원(소음, 기기 불량, 환불 요청 등)을 직접 처리하는 스트레스가 있다.","socialDetail":"시민의 여가·오락 수요를 충족시키는 서비스직으로 필요성은 있으나, 사회적 인식은 높지 않다. 청소년에게는 여가 활동을 제공하는 역할을 하지만, 일부 청소년 보호 규정(심야 출입 제한) 관리 의무도 부담한다."},"detailReady":{"curriculum":["별도 자격증이나 학력 요건 없음; 고객 서비스 마인드 필수","기본 컴퓨터·인터넷 활용 능력(PC방 업종 필요)","볼링·당구 관련 시설 장비 사용법 현장 교육","식품위생교육(매장에서 식음료 판매 시 이수 필요)"],"recruit":["워크넷, 알바천국, 사람인 등 구인 플랫폼","노래방·PC방·볼링장 등 직접 방문 구직","관광·오락 시설 프랜차이즈 본사 채용","리조트·복합 엔터테인먼트 시설 정직원 채용"],"training":["매장 관리자(점장)로 승진 후 멀티점 슈퍼바이저","PC방·노래방 창업 또는 프랜차이즈 가맹","VR·AR 체험관 등 신형 오락 시설 분야로 전환","레저시설 운영 전문가, 이벤트 플래너로 진로 전환"]},"sidebarJobs":["카지노딜러","공연기획자","여행안내원","주방보조원","안내·접수원 및 전화교환원"],"sidebarMajors":["레저스포츠학과","관광경영학과","관광경영과"],"sidebarCerts":["유기시설·유기기구 안전검사","식품위생교육이수증","PC방 운영관련 지식"],"heroTags":["오락시설","PC방","노래방","볼링장","서비스직","오락서비스"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=390"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=390"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=390"},{"id":2,"text":"한국콘텐츠진흥원","url":"https://www.kocca.kr/"}],"trivia":[{"id":1,"text":"한국콘텐츠진흥원","url":"https://www.kocca.kr/"},{"id":2,"text":"한국노래문화산업협회","url":"https://www.karaokek.or.kr/"},{"id":3,"text":"골프존 공식 자료","url":"https://www.golfzon.com/"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=390"}],"detailWlb.socialDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=390"}]}}' WHERE id = '1765283479325614';

UPDATE jobs SET user_contributed_json = '{"way":"주방보조원이 되기 위해 특별한 자격증이나 학력 요건은 없다.[1] 일반 식당, 호텔 주방, 단체급식 업체, 패스트푸드 매장 등에서 현장 지원서를 내거나 알바천국·워크넷 등을 통해 취업한다.[2] 기본 위생 관념과 체력이 가장 중요하며, 조리에 관심이 있는 사람은 현장 경험을 쌓으면서 조리기능사 자격을 병행 취득하는 것이 일반적인 성장 경로다.[1] 경력을 쌓으면 조리 보조에서 보조 요리사, 정식 조리사로 단계적으로 성장할 수 있다.[2] 쿠킹 스쿨 입학이나 전문 조리학교 진학을 통해 체계적인 조리 기술을 배우는 경로도 있다.[1]","overviewSalary":{"sal":"연봉 중위값은 약 2,200만 원으로 최저임금에 근접한 수준이다.[1] 단체급식 정규직의 경우 복지 혜택이 포함되어 실질 처우가 다소 나은 편이다.[2] 호텔이나 고급 레스토랑의 경우 수습 기간 후 급여가 다소 높아질 수 있다.[1]","source":"워크넷, 커리어넷 직업백과(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 현 수준을 유지하거나 소폭 감소할 것으로 전망된다.[1] 자동화 조리 설비(로봇 요리사, 자동 식기 세척기 등)의 보급으로 일부 단순 보조 업무가 줄어들 수 있다.[2] 그러나 외식 산업 규모가 유지되고 있어 전체 수요는 급격히 줄지 않을 것으로 보인다.[1]","source":"커리어넷 직업백과, 한국외식산업연구원(2024)"},"trivia":"유명 셰프들 중 상당수는 주방 보조 또는 홀 직원으로 시작하여 수십 년간 경험을 쌓아 자신의 레스토랑을 연 사례가 많다.[1] 위생이 불량한 주방은 집단 식중독의 발원지가 될 수 있어, 주방보조원의 위생 관리가 공중 보건과 직결된다.[2] 프랑스 미슐랭 3스타 레스토랑의 주방에서는 주방보조원(Commis)도 엄격한 위생 규정과 동선 준수를 요구받는다.[3] 한국 호텔 주방에서 ''스테이지(stage)''는 무급 또는 소액 수당을 받으며 기술을 배우는 수습 단계를 의미한다.[1]","detailWlb":{"wlb":"보통이하","social":"보통이하","wlbDetail":"이른 아침 재료 준비부터 영업 종료 후 청소까지 근무 시간이 길다. 주방 환경 특성상 더위, 기름 냄새, 소음에 지속적으로 노출되며, 서서 일하는 시간이 많아 체력 소모가 크다. 명절·주말이 가장 바쁜 시간이어서 가족과 함께하기 어렵다.","socialDetail":"주방보조원 없이는 음식 서비스 자체가 불가능하다. 하지만 사회적 인식은 낮은 편이며, 처우 개선과 직업 인식 제고가 과제로 남아 있다. 최근 ''쿡방'' 문화 확산으로 조리 직종 전반에 대한 관심이 높아지고 있다."},"detailReady":{"curriculum":["별도 자격요건 없음; 식품위생교육 이수 권장","조리기능사(한식·양식·중식·일식·복어) 자격증 취득 준비","조리학원 수강 또는 조리과 진학으로 기술 체계화","위생 관련 교육 이수(HACCP 기초 교육)"],"recruit":["워크넷, 알바천국, 사람인 등 구인 플랫폼","호텔 조리부 인원 수시 채용","단체급식 업체(아워홈, 삼성웰스토리, 현대그린푸드) 채용","음식점 직접 방문 구직"],"training":["조리기능사 → 조리산업기사 단계적 취득","보조 요리사 → 정식 조리사 → 주방장(Chef)으로 성장","조리 전문 학교(조리고등학교, 한국관광고) 재진학 또는 조리대학 입학","특정 요리(파티시에·스시 등) 전문화로 고급 레스토랑 진출"]},"sidebarJobs":["주방장","요리연구가","바리스타","음식서비스관리자","영양사","푸드스타일리스트"],"sidebarMajors":["식품조리학과","외식산업과","식품영양학과","식품공학과"],"sidebarCerts":["조리기능사","위생사","식품위생관리사","HACCP관리사"],"heroTags":["주방보조","조리보조","주방알바","식당보조","조리기능사"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=365"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=365"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=365"},{"id":2,"text":"한국외식산업연구원","url":"https://www.kfiri.org/"}],"trivia":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=365"},{"id":2,"text":"식품의약품안전처","url":"https://www.mfds.go.kr/"},{"id":3,"text":"미슐랭 가이드 공식 사이트","url":"https://guide.michelin.com/"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=365"}],"detailWlb.socialDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=365"}]}}' WHERE id = '1765283374840392';

UPDATE jobs SET user_contributed_json = '{"way":"대중무용수가 되려면 어린 시절부터 무용 학원이나 전문 댄스 스튜디오에서 장르별(걸스힙합, 왁킹, 팝핀, 재즈댄스 등) 훈련을 시작하는 것이 일반적이다.[1] 대학교 무용학과·실용무용학과 진학 후 포트폴리오를 쌓거나, 댄스 크루 활동을 통해 실력을 인정받아 K-pop 백댄서 오디션이나 공연 에이전시에 등록한다.[2] SM·YG·HYBE 등 대형 엔터테인먼트 회사의 댄서 오디션, 공중파 방송사 댄스팀 오디션에 합격하거나, 뮤지컬·공연 기획사에 소속 댄서로 계약하는 방식이 있다.[1] 최근에는 유튜브·인스타그램에서 댄스 콘텐츠를 통해 팔로워를 확보한 후 브랜드 협업이나 공연 섭외로 진출하는 경로도 생겨났다.[2]","overviewSalary":{"sal":"연봉 중위값은 약 2,600만 원이다.[1] 수입 편차가 매우 크며, K-pop 1군 아티스트의 백댄서는 월 수백만 원의 안정적인 계약이 가능하나, 프리랜서 댄서는 공연 건별 수입으로 생활이 불안정하다.[2] 유명 댄서의 경우 강습비, 브랜드 광고, 유튜브 수익 등으로 연 1억 원 이상도 가능하다.[1]","source":"워크넷, 커리어넷 직업백과(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 보통 수준을 유지하거나 소폭 증가할 것으로 전망된다.[1] K-pop 한류 확산에 따라 K-팝 댄서 수요가 글로벌로 확대되고 있으며, 유튜브·틱톡 등 숏폼 댄스 콘텐츠 수요도 급증하고 있다.[2] 다만 경쟁이 치열하고 신체 부상 위험으로 장기 활동이 어려운 구조적 한계가 있다.[1]","source":"커리어넷 직업백과, 한국콘텐츠진흥원(2024)"},"trivia":"BTS의 전 세계 콘서트 투어에 동행하는 백댄서 팀은 연간 수천만 원의 계약으로 활동하며, K-pop 댄서의 위상을 대폭 높였다.[1] 댄서는 한 공연을 위해 보통 3~6개월의 집중 연습을 하며, 실제 공연 시간의 10배 이상을 훈련에 쏟는다.[2] ''스트릿댄서''로 시작하여 세계 규모 배틀 대회(BOTY, R16 코리아)를 통해 국제 무대로 진출하는 경로도 활발하다.[3] 뮤지컬 분야에서는 댄서가 배우·노래를 병행하는 ''댄서 배우''로 성장하는 경우가 늘고 있다.[1]","detailWlb":{"wlb":"낮음","social":"보통이상","wlbDetail":"공연·투어 시즌에는 야간 연습과 주말 공연이 집중되어 개인 시간이 거의 없다. 신체 부상(무릎, 발목, 허리) 위험이 높으며 무용수 활동 기간이 보통 30~35세까지로 제한적이다. 프리랜서 활동 시 수입 불안정성이 크고 다음 공연 계약에 대한 지속적인 불안감이 있다.","socialDetail":"K-pop, 뮤지컬, 방송 등 대중문화 산업을 지탱하는 핵심 예술인으로 문화적 가치가 높다. 한류 확산으로 한국 댄스 문화(K-dance)가 세계 팬들에게 전파되고 있으며, 글로벌 문화 외교 역할도 하고 있다."},"detailReady":{"curriculum":["어린 시절부터 댄스 스튜디오에서 장르별 기초 훈련 시작","대학교 무용학과, 실용무용학과 진학으로 이론·실기 체계화","댄스 크루 결성 또는 기존 크루 합류: 공연·배틀 경험 축적","SNS 댄스 영상 업로드를 통한 포트폴리오 및 팔로워 확보"],"recruit":["K-pop 엔터테인먼트사 댄서 오디션 (SM·YG·HYBE·JYP 외 다수)","뮤지컬·공연 기획사 댄서 오디션","댄스팀 에이전시 등록 후 기업 행사·방송 출연 계약","댄스 경연대회(K-POP 월드 페스티벌, R16 등) 입상으로 인지도 확보"],"training":["해외 워크숍·배틀 참가로 글로벌 수준의 기술 강화","안무가(choreographer)로 전환: 가수·그룹의 안무 직접 제작","댄스 강사 활동 (스튜디오·대학 강사)","댄스 유튜버·콘텐츠 크리에이터로 독립 활동"]},"sidebarJobs":["무용가","안무가","뮤지컬배우","배우","공연기획자"],"sidebarMajors":["무용학과","무용과","체육학과","실용음악과"],"sidebarCerts":["무용지도사","스포츠지도사(에어로빅)","생활체육지도사"],"heroTags":["댄서","K-pop댄서","백댄서","대중무용수","안무가","스트릿댄스"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=450"},{"id":2,"text":"한국콘텐츠진흥원","url":"https://www.kocca.kr/"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"한국콘텐츠진흥원","url":"https://www.kocca.kr/"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=450"},{"id":2,"text":"한국콘텐츠진흥원","url":"https://www.kocca.kr/"}],"trivia":[{"id":1,"text":"한국콘텐츠진흥원","url":"https://www.kocca.kr/"},{"id":2,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=450"},{"id":3,"text":"R16 Korea 공식 사이트","url":"https://www.r16korea.com/"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=450"}],"detailWlb.socialDetail":[{"id":1,"text":"한국콘텐츠진흥원","url":"https://www.kocca.kr/"}]}}' WHERE id = '1765283469844377';

UPDATE jobs SET user_contributed_json = '{"way":"제화원이 되려면 제화 기능을 전문적으로 배우는 직업훈련원이나 구두학원에 입학하거나, 제화 공방·공장에서 도제식 교육을 받는 것이 일반적이다.[1] 한국산업인력공단 시행 제화기능사 자격증 취득이 취업에 유리하며, 제화 공방, 수제화 브랜드, 신발 제조업체 등에 취업한다.[2] 성수동(서울) 수제화 거리, 부산 신발 산업 단지 등에서 전통 도제 방식의 교육을 받는 경로도 있다.[1] 경력이 쌓이면 수제화 브랜드를 창업하거나 고급 맞춤 구두 장인(코르도네)으로 독립할 수 있다.[2] 패션 브랜드의 신발 라인 디자인·개발팀과 협업하는 방향으로도 진출할 수 있다.[1]","overviewSalary":{"sal":"연봉 중위값은 약 2,800만 원이다.[1] 숙련 기능인의 경우 고급 수제화 제작으로 연 5,000만 원 이상도 가능하다.[2] 공장 대량 생산직은 최저임금 수준이나, 장인 급의 맞춤 제화원은 프리미엄 가격을 받을 수 있다.[1]","source":"워크넷, 커리어넷 직업백과(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 다소 감소할 것으로 전망된다.[1] 저가 수입산 신발과 기계화 대량 생산으로 국내 제화 산업이 전반적으로 위축되고 있다.[2] 그러나 프리미엄 수제화, 맞춤 교정화, 친환경 소재 신발 등 고부가가치 분야는 소비자 수요가 있어 전문 기능인의 성장 가능성은 유지된다.[1]","source":"커리어넷 직업백과, 한국신발산업협회(2024)"},"trivia":"이탈리아 구두 브랜드 ''페라가모'', ''구찌'' 등은 피렌체의 수제화 장인 전통에서 시작된 패션 제국이다.[1] 서울 성수동은 ''수제화 골목''으로 유명하며, 1960~70년대에는 한국 최대 신발 생산지였다. 현재는 수제화 브랜드와 공방이 밀집해 수공예 부활의 상징이 되고 있다.[2] 고급 수제 구두 한 켤레를 만드는 데는 200~300개의 공정과 약 40시간의 작업이 필요하다.[3] 제화원이 사용하는 ''라스트(last·목형)''는 신발의 형태를 결정하는 나무·플라스틱 주형으로, 제화원마다 독자적인 라스트를 보유하여 고객의 발에 맞는 신발을 만든다.[1]","detailWlb":{"wlb":"보통이상","social":"보통이하","wlbDetail":"전통 수공예 제조업의 특성상 주로 낮 시간 작업이고 야간·주말 강제 근무는 드물다. 다만 주문 납기가 촉박한 경우 집중 작업 기간이 발생한다. 앉아서 세밀한 수작업을 오래 하는 특성상 눈 피로, 허리 통증, 손·손목 과부하가 직업병으로 발생할 수 있다.","socialDetail":"신발은 인간의 기본 생활에 필요한 필수품을 만드는 기능직이다. 사회적 인식은 높지 않은 편이나, 교정화 제작(장애인·족부 질환자용)이나 전통 기법 보존 분야에서는 전문성이 높이 평가된다. 최근 수공예·장인 문화의 재조명으로 제화 기능인에 대한 관심이 높아지고 있다."},"detailReady":{"curriculum":["제화 관련 직업훈련원·구두학원 등록: 재단, 갑피 제작, 창 부착 등 기초 실기","제화기능사 자격시험 준비: 필기(피혁재료학, 제화이론) + 실기(신발 제작)","서울 성수동·부산 등 제화 공방에서 도제 교육 병행","패션 디자인 기초 학습으로 신발 디자인 역량 강화"],"recruit":["수제화 브랜드 및 공방 취업(성수동 수제화 거리, 부산 신발 단지)","신발 제조업체 기능직 채용","스포츠 브랜드(아디다스·나이키 국내 공장) 기술직 채용","의족·교정화 전문 의지·보조기 업체 채용"],"training":["제화기능사 → 제화기능장 상위 자격 취득","고급 수제화 브랜드 창업 (성수동·강남 등 프리미엄 시장)","교정화 전문가 과정 이수: 의료 보조기구 분야 진출","해외 제화 명가 연수(이탈리아·영국 코르도네 과정)"]},"sidebarJobs":["의복수선원","한복제조원","양장·양복제조원","패션디자이너","의상디자이너"],"sidebarMajors":["패션디자인학과","패션디자인과","의류·의상학과"],"sidebarCerts":["제화기능사","제화기능장","피혁공예기능사","패션디자인산업기사"],"heroTags":["제화원","수제화","구두제작","제화기능사","성수동","수공예"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=480"},{"id":2,"text":"한국산업인력공단","url":"https://www.hrdkorea.or.kr/"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=480"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=480"},{"id":2,"text":"한국신발산업협회","url":"https://www.kofsi.or.kr/"}],"trivia":[{"id":1,"text":"이탈리아 패션협회(CNA)","url":"https://www.cna.it/"},{"id":2,"text":"서울시 성수동 공방 사업","url":"https://www.seoul.go.kr/"},{"id":3,"text":"한국신발산업협회","url":"https://www.kofsi.or.kr/"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=480"}],"detailWlb.socialDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=480"}]}}' WHERE id = '176528337216746';